import { workflow, node, trigger } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const httpRequest = node({
  type: 'n8n-nodes-base.httpRequest',
  version: 4.3,
  config: {
    name: 'HTTP Request',
    parameters: {
      method: 'GET',
      url: ''
    }
  }
});

export default workflow('manual-http', 'Manual Trigger - HTTP Request')
  .add(manualTrigger)
  .to(httpRequest);
